     1→import { useCallback } from 'react';
     2→import { useShallow } from 'zustand/shallow';
     3→import { useRootStore } from '~/store';
     4→import {
     5→  getPointsProducts,
     6→  getPointsBalance,
     7→  getParameterPointsProgram,
     8→} from '../services';
     9→import {
    10→  PointsProductsStatus,
    11→  PointsBalanceStatus,
    12→  ParameterPointsProgramStatus,
    13→} from '../models';
    14→
    15→export function usePoints() {
    16→  const pointsProducts = useRootStore(useShallow((state) => state.pointsProducts));
    17→  const pointsBalance = useRootStore(useShallow((state) => state.pointsBalance));
    18→  const parameterPointsProgram = useRootStore(
    19→    useShallow((state) => state.parameterPointsProgram)
    20→  );
    21→
    22→  const requestInitialData = useCallback(async () => {
    23→    await Promise.all([
    24→      getPointsBalance(),
    25→      getPointsProducts(),
    26→      getParameterPointsProgram(),
    27→    ]);
    28→  }, []);
    29→
    30→  const requestPointsBalance = useCallback(async () => {
    31→    await getPointsBalance();
    32→  }, []);
    33→
    34→  const requestPointsProducts = useCallback(async () => {
    35→    await getPointsProducts();
    36→  }, []);
    37→
    38→  const requestParameterization = useCallback(async () => {
    39→    await getParameterPointsProgram();
    40→  }, []);
    41→
    42→  const clear = useCallback(() => {
    43→    const { pointsProductsActions } = useRootStore.getState();
    44→    pointsProductsActions.reset();
    45→  }, []);
    46→
    47→  return {
    48→    points: pointsBalance.points,
    49→    isLoadingBalance: pointsBalance.status === PointsBalanceStatus.LOADING,
    50→    isErrorBalance: pointsBalance.status === PointsBalanceStatus.ERROR,
    51→
    52→    products: pointsProducts.products,
    53→    isLoadingProducts: pointsProducts.status === PointsProductsStatus.LOADING,
    54→    isErrorProducts: pointsProducts.status === PointsProductsStatus.ERROR,
    55→
    56→    pointsQuantity: parameterPointsProgram.pointsQuantity,
